// SPDX-License-Identifier: MIT
pragma solidity ^0.8.7;

contract DegreeCertification {
    struct Certificate {

        string idNumber; // sô cccd
        string studentID; // Mã sinh viên
        string name; // Họ tên người được cấp
        string degree; // Tên văn bằng được cấp
        string institution; // Cơ sở đào tạo cấp bằng
        uint256 dateIssued; // Ngày cấp
        string numberSign; // Số hiệu
        string referenceNumber; // Số vào sổ
        bool isValid;
    }

    mapping(bytes32 => Certificate) private certificates;
    address public owner;

    event CertificateIssued(bytes32 indexed certHash, string idNumber, string studentID, string name, string degree, string institution, uint256 dateIssued, string numberSign, string referenceNumber);
    event CertificateRevoked(bytes32 indexed certHash);

    modifier onlyOwner() {
        require(msg.sender == owner, "Only the owner can perform this action");
        _;
    }

    constructor() {
        owner = msg.sender;
    }

    // Để phát hành chứng chỉ mới.
    function issueCertificate(string memory _idNumber, string memory _studentID, string memory _name, string memory _degree, string memory _institution, uint256 _dateIssued, string memory _numberSign, string memory _referenceNumber) public onlyOwner returns (bytes32) {
        bytes32 certHash = keccak256(abi.encodePacked(_idNumber, _studentID, _name, _degree, _institution, _dateIssued, _numberSign, _referenceNumber));
        certificates[certHash] = Certificate(_idNumber, _studentID, _name, _degree, _institution, _dateIssued, _numberSign, _referenceNumber, true);
        emit CertificateIssued(certHash, _idNumber, _studentID, _name, _degree, _institution, _dateIssued, _numberSign, _referenceNumber);
        return certHash;
    }

    // Để thu hồi chứng chỉ
    function revokeCertificate(bytes32 _certHash) public onlyOwner {
        require(certificates[_certHash].isValid, "Certificate is not valid");
        certificates[_certHash].isValid = false;
        emit CertificateRevoked(_certHash);
    }

    // Để kiểm tra thông tin chứng chỉ.
    function verifyCertificate(bytes32 _certHash) public view returns (string memory, string memory, string memory, string memory, string memory, uint256, string memory, string memory, bool) {
        Certificate memory cert = certificates[_certHash];
        require(cert.isValid, "Certificate is not valid");
        return (cert.idNumber, cert.studentID, cert.name, cert.degree, cert.institution, cert.dateIssued, cert.numberSign, cert.referenceNumber, cert.isValid);
    }
}
